// NODE 02 · PFLICHTFELDER VALIDIEREN
const body = $input.first().json.body || $input.first().json;
const errors = [], warnings = [];
const required = {typ:'Objekttyp',ang:'Angebotstyp',adr:'Adresse',fl:'Wohnfläche',zi:'Zimmer',pr:'Preis',zu:'Zustand'};
for(const [k,l] of Object.entries(required)){
  if(!body[k]||String(body[k]).trim()==='') errors.push('Pflichtfeld fehlt: '+l);
}
if(body.fl&&parseFloat(body.fl)<5) errors.push('Wohnfläche zu klein');
if(body.pr){
  const p=parseInt(String(body.pr).replace(/[^0-9]/g,''));
  if(p<100) errors.push('Preis zu niedrig — CHF-Betrag eingeben');
  if(body.ang==='Verkauf'&&p<50000) warnings.push('Kaufpreis unter CHF 50.000 — prüfen');
  if(body.ang==='Vermietung'&&p>50000) warnings.push('Mietpreis über CHF 50.000 — prüfen');
}
if(body.bj&&(parseInt(body.bj)<1800||parseInt(body.bj)>2030)) errors.push('Baujahr ungültig');
if(errors.length>0) return [{json:{_error:true,step:'Eingabe-Validierung',error:errors.join(' | '),warnings}}];
return [{json:{_error:false,body,warnings,validatedAt:new Date().toISOString()}}];

// NODE 03 · BILDER VALIDIEREN
const input = $input.first().json;
if(input._error) return [{json:input}];
const body=input.body, bilder=Array.isArray(body.bilder)?body.bilder:[];
const errors=[],warnings=[],validBilder=[];
const VALID=['image/jpeg','image/png','image/webp'];
if(bilder.length===0) warnings.push('Keine Bilder — Exposé ohne Bildbeschreibungen');
for(let i=0;i<Math.min(bilder.length,10);i++){
  const b=bilder[i],be=[];
  if(!b.type||!VALID.includes(b.type)) be.push('Bild '+(i+1)+': ungültiger Typ');
  if(!b.data||b.data.length<100) be.push('Bild '+(i+1)+': Daten fehlen');
  if(b.data&&b.data.length*0.75>5*1024*1024) be.push('Bild '+(i+1)+' zu gross (max 5 MB)');
  if(be.length>0) errors.push(...be);
  else validBilder.push({...b,index:i,label:b.label||(i===0?'Hauptbild':'Bild '+(i+1)),mediaType:b.type});
}
if(errors.length>0) return [{json:{_error:true,step:'Bild-Validierung',error:errors.join(' | '),warnings}}];
return [{json:{...input,validBilder,bildAnzahl:validBilder.length,bildWarnings:warnings}}];

// NODE 04b · VORLAGE VERARBEITEN
const prev = $('03 · Bilder validieren').first().json;
if(prev._error) return [{json:prev}];

const vorlageUrl = prev.body?.vorlageUrl || '';
let vorlageText = '';
let vorlageAnalyse = '';

if(vorlageUrl) {
  try {
    const raw = $input.first().json.data || $input.first().json.body || '';
    const text = typeof raw === 'string' ? raw : JSON.stringify(raw);

    // HTML-Tags entfernen, Text extrahieren
    vorlageText = text
      .replace(/<script[\s\S]*?<\/script>/gi, '')
      .replace(/<style[\s\S]*?<\/style>/gi, '')
      .replace(/<[^>]+>/g, ' ')
      .replace(/\s+/g, ' ')
      .trim()
      .slice(0, 4000); // Max 4000 Zeichen für den Prompt

    vorlageAnalyse = vorlageText.length > 100
      ? `VORLAGE-ANALYSE:\nDer Makler hat folgendes bestehendes Exposé als Stilvorlage hinterlegt (URL: ${vorlageUrl}).\nAnalysiere Schreibstil, Aufbau, Ton, Sprache und CI dieses Textes GENAU.\nDas neue Exposé soll in GLEICHEM Stil, gleicher Struktur und gleichem Ton verfasst sein — nur mit den neuen Objektdaten.\n\nVORLAGE-TEXT (gekürzt):\n${vorlageText}\n\n`
      : '';
  } catch(e) {
    vorlageAnalyse = '';
  }
}

return [{json:{...prev,vorlageUrl,vorlageAnalyse,vorlageGeladen:!!vorlageText}}];

// NODE 05 · DATEN ANREICHERN
const input = $input.first().json;
if(input._error) return [{json:input}];
const body=input.body;
const preisRaw=parseInt(String(body.pr).replace(/[^0-9]/g,''));
const preisFormatiert=new Intl.NumberFormat('de-CH').format(preisRaw);
const preisLabel=body.ang==='Vermietung'?'Mietzins':'Kaufpreis';
const kantone={ZH:'Zürich',ZG:'Zug',BS:'Basel-Stadt',GE:'Genf',BE:'Bern',LU:'Luzern',AG:'Aargau',SZ:'Schwyz',NW:'Nidwalden',OW:'Obwalden',UR:'Uri',GL:'Glarus',AR:'Appenzell AR',AI:'Appenzell IR',SG:'St. Gallen',GR:'Graubünden',TG:'Thurgau',SH:'Schaffhausen',TI:'Tessin',VD:'Waadt',VS:'Wallis',FR:'Freiburg',NE:'Neuenburg',JU:'Jura',SO:'Solothurn',BL:'Basel-Landschaft'};
const kantonName=kantone[body.kt]||body.kt||'';
const adresseVoll=body.adr+(kantonName?', '+kantonName:'');
const alter=body.bj?(2025-parseInt(body.bj)):null;
const objektAlter=alter===null?'':alter<=0?'Neubau':alter<=5?'nahezu neu':alter+' Jahre alt';
const jahreSeitReno=body.re?(2025-parseInt(body.re)):null;
const renovationsInfo=jahreSeitReno===null?'':jahreSeitReno<=0?'frisch renoviert':jahreSeitReno<=3?'kürzlich renoviert':jahreSeitReno<=10?'vor '+jahreSeitReno+' Jahren renoviert':'Renovation '+body.re;
const merkmale=Array.isArray(body.merkmale)&&body.merkmale.length>0?body.merkmale.join(', '):'keine besonderen Merkmale';
return [{json:{...input,enriched:{preisRaw,preisFormatiert,preisLabel,kantonName,adresseVoll,objektAlter,renovationsInfo,merkmale},enrichedAt:new Date().toISOString()}}];

// NODE 06 · SYSTEM PROMPT AUFBAUEN
const input = $input.first().json;
if(input._error) return [{json:input}];
const body=input.body, e=input.enriched;
const hatVorlage = !!input.vorlageAnalyse;

const stilMap={'Professionell':'Sachlich, präzise, seriös. Keine Superlative.','Emotional':'Wärmend, einladend. Lässt den Leser sich vorstellen dort zu leben.','Premium':'Exklusiv, distinguiert. Für anspruchsvolle Käufer.','Familiär':'Herzlich, praktisch. Alltag und Familie betonen.','Wie Vorlage':'Exakt wie die analysierte Vorlage.'};
const zgMap={'Familien':'Schulen, Garten, Platz, Gemeinschaft betonen.','Paare / Singles':'Lage, Lifestyle, moderne Küche betonen.','Investoren':'Rendite, Substanz, Lage-Entwicklung betonen.','Keine Vorgabe':'Breite Ansprache.'};

const systemPrompt=`Du bist der beste Immobilien-Texter der Schweiz mit 20 Jahren Erfahrung.

GRUNDSÄTZE:
- Nur Schweizer Hochdeutsch
- Keine Klischees, keine leeren Versprechen
- Bilder präzise analysieren, Details natürlich einweben
- Jeder Satz trägt zum Gesamteindruck bei
${hatVorlage ? `
WICHTIG — STILVORLAGE:
Der Makler hat ein bestehendes Exposé als Vorlage hinterlegt.
Analysiere dessen Stil, Ton, Aufbau und Sprache SEHR GENAU.
Das neue Exposé muss sich anfühlen wie vom selben Texter — gleiche Stimme, gleiche Struktur, gleicher CI-Ton.
Nur die Objektdaten werden ausgetauscht.
` : `STIL: ${stilMap[body.ton]||stilMap['Professionell']}`}
ZIELGRUPPE: ${zgMap[body.zg]||zgMap['Keine Vorgabe']}

Gib exakt diese zwei Blöcke aus:
===VOLLSTAENDIG===
[500–700 Wörter: emotionaler Einstieg, alle Details, Bilder eingeflochten]
===PORTAL===
[Max. 1800 Zeichen: kompakt, alle Pflichtinfos, für ImmoScout24 / Homegate]`;

return [{json:{...input,systemPrompt}}];

// NODE 07 · USER PROMPT AUFBAUEN
const input = $input.first().json;
if(input._error) return [{json:input}];
const body=input.body, e=input.enriched;
const bilder=input.validBilder||[];
const bildInfo=bilder.length>0?bilder.map((b,i)=>'Bild '+(i+1)+' ('+b.label+')').join(', '):'Keine Bilder';
const userPrompt=`${input.vorlageAnalyse||''}OBJEKT: ${body.typ} | ${body.ang} | ${e.adresseVoll}
FLÄCHE: ${body.fl} m² | ZIMMER: ${body.zi}${body.st_?' | '+body.st_:''}
BAUJAHR: ${body.bj||'–'}${e.objektAlter?' ('+e.objektAlter+')':''}${e.renovationsInfo?' | '+e.renovationsInfo:''}
${e.preisLabel}: CHF ${e.preisFormatiert}
ZUSTAND: ${body.zu} | HEIZUNG: ${body.hz||'–'} | PARKIERUNG: ${body.pk||'keine'}
MERKMALE: ${e.merkmale}
WEITERE DETAILS: ${body.we||'keine'}
LAGE: ${body.um||'–'}
ÖV: ${body.ov||'–'} | EINKAUF/SCHULEN: ${body.sc||'–'}
BILDER: ${bildInfo}

${bilder.length>0?'Analysiere zuerst die Bilder sorgfältig. Integriere visuelle Details natürlich in beide Texte.':''}
Erstelle dann die zwei Versionen exakt wie im System Prompt vorgegeben.`;
return [{json:{...input,userPrompt}}];

// NODE 08 · CLAUDE MESSAGE BAUEN
const input = $input.first().json;
if(input._error) return [{json:input}];
const bilder=input.validBilder||[], content=[];
for(const b of bilder){
  content.push({type:'image',source:{type:'base64',media_type:b.mediaType||'image/jpeg',data:b.data}});
  content.push({type:'text',text:'↑ '+b.label+' (Bild '+(b.index+1)+' von '+bilder.length+')'});
}
content.push({type:'text',text:input.userPrompt});
return [{json:{...input,apiBody:{model:'claude-sonnet-4-6',max_tokens:3000,system:input.systemPrompt,messages:[{role:'user',content}]}}}];

// NODE 10 · API ANTWORT PRÜFEN
const r=$input.first().json;
if(r.error){
  const codes={'authentication_error':'Ungültiger API Key — CLAUDE_API_KEY in n8n prüfen.','rate_limit_error':'Rate Limit — 60 Sek. warten.','overloaded_error':'Claude überlastet — erneut versuchen.'};
  return [{json:{_error:true,step:'Claude API',error:codes[r.error.type]||'API Fehler: '+r.error.message}}];
}
const rawText=r.content?.[0]?.text||'';
if(!rawText||rawText.length<100) return [{json:{_error:true,step:'API Antwort',error:'Claude hat keinen Text zurückgegeben — bitte erneut versuchen'}}];
return [{json:{rawText,usage:r.usage||{},model:r.model||'claude-sonnet-4-6'}}];

// NODE 11 · VERSIONEN EXTRAHIEREN
const input=$input.first().json;
if(input._error) return [{json:input}];
const raw=input.rawText;
function extr(text,start,end){
  const si=text.indexOf(start);if(si===-1)return null;
  const after=text.slice(si+start.length);if(!end)return after.trim();
  const ei=after.indexOf(end);return ei===-1?after.trim():after.slice(0,ei).trim();
}
let vollstaendig=extr(raw,'===VOLLSTAENDIG===','===PORTAL===');
let portal=extr(raw,'===PORTAL===',null);
if(!vollstaendig) vollstaendig=extr(raw,'=== VOLLSTÄNDIGES EXPOSÉ ===','===')||raw.trim();
if(!portal) portal=vollstaendig.slice(0,1800);
return [{json:{...input,vollstaendig,portal}}];

// NODE 12 · VOLLSTÄNDIGES EXPOSÉ PRÜFEN
const input=$input.first().json;
if(input._error) return [{json:input}];
const text=input.vollstaendig, warnings=[];
const worte=text.trim().split(/\s+/).filter(w=>w.length>0).length;
if(worte<200) warnings.push('Exposé kurz ('+worte+' Wörter)');
if(worte>950) warnings.push('Exposé lang ('+worte+' Wörter)');
const klischees=['einzigartiges Schmuckstück','Traumlage','traumhaft','einzigartig'];
const gefunden=klischees.filter(k=>text.toLowerCase().includes(k.toLowerCase()));
if(gefunden.length>0) warnings.push('Klischees: '+gefunden.join(', '));
return [{json:{...input,qcVollstaendig:{worte,zeichen:text.length,warnings,ok:warnings.length===0}}}];

// NODE 13 · PORTAL-VERSION PRÜFEN
const input=$input.first().json;
if(input._error) return [{json:input}];
let portal=input.portal; const warnings=[]; let trimmed=false;
if(portal.length>1800){
  let cut=portal.slice(0,1780);
  const last=Math.max(cut.lastIndexOf('.'),cut.lastIndexOf('!'),cut.lastIndexOf('?'));
  portal=last>1600?cut.slice(0,last+1):cut.trim()+'...';
  trimmed=true;warnings.push('Portal auf '+portal.length+' Zeichen gekürzt');
}
if(portal.length<300) warnings.push('Portal-Version sehr kurz');
if(!portal.includes('m²')) warnings.push('Fläche (m²) fehlt in Portal-Version');
if(!portal.includes('CHF')) warnings.push('Preis (CHF) fehlt in Portal-Version');
return [{json:{...input,portal,qcPortal:{zeichen:portal.length,trimmed,warnings,ok:!trimmed&&warnings.length===0}}}];

// NODE 14 · ZUSAMMENFÜHREN
const input=$input.first().json;
if(input._error) return [{json:input}];
const allWarnings=[...(input.warnings||[]),...(input.bildWarnings||[]),...(input.qcVollstaendig?.warnings||[]),...(input.qcPortal?.warnings||[])].filter(Boolean);
return [{json:{...input,allWarnings}}];

// NODE 15 · FINAL QC
const input=$input.first().json;
if(input._error) return [{json:input}];
const v=input.vollstaendig||'',p=input.portal||'',c=[];
if(v.length<50) c.push('Vollständiges Exposé fehlt');
if(p.length<50) c.push('Portal-Version fehlt');
if(p.length>1800) c.push('Portal überschreitet 1800 Zeichen');
if(c.length>0) return [{json:{_error:true,step:'Final QC',error:c.join(' | ')}}];
return [{json:{...input,finalQcPassed:true}}];

// NODE 17 · RESPONSE FORMATIEREN
const input=$input.first().json;
if(input._error) return [{json:input}];
const e=input.enriched||{},body=input.body||{};
const zusammenfassung=[body.zi?body.zi+'-Zimmer-'+body.typ:body.typ,body.fl?body.fl+' m²':null,e.adresseVoll||body.adr,e.preisFormatiert?'CHF '+e.preisFormatiert:null].filter(Boolean).join(' · ');
return [{json:{success:true,vollstaendig:input.vollstaendig,portal:input.portal,meta:{zusammenfassung,bildAnzahl:input.bildAnzahl||0,worte:input.qcVollstaendig?.worte||0,zeichenPortal:input.qcPortal?.zeichen||0,vorlageVerwendet:input.vorlageGeladen||false,model:input.model||'claude-sonnet-4-6',generatedAt:new Date().toISOString()},warnings:input.allWarnings||[]}}];

// NODE 18 · FEHLER-RESPONSE
const input=$input.first().json;
const msg=typeof input.error==='string'?input.error:JSON.stringify(input.error||'Unbekannter Fehler');
return [{json:{success:false,error:msg,step:input.step||'Verarbeitung',errorAt:new Date().toISOString()}}];

// NODE 20 · FEHLER-HANDLER API
const e=$input.first().json;
const msg=e?.message||e?.error?.message||'Verbindungsfehler';
const code=String(e?.statusCode||'');
const map={'401':'Ungültiger API Key.','403':'Zugriff verweigert.','429':'Rate Limit — 60 Sek. warten.','529':'Claude überlastet.'};
return [{json:{_error:true,step:'Claude API (HTTP)',error:map[code]||'API Fehler: '+msg}}];

// NODE 21 · VORLAGE-FEHLER-HANDLER
// Wenn die Vorlage-URL nicht geladen werden kann, weitermachen ohne Vorlage
const prev = $('03 · Bilder validieren').first().json;
if(prev._error) return [{json:prev}];
return [{json:{...prev,vorlageUrl:'',vorlageAnalyse:'',vorlageGeladen:false,vorlageWarning:'Vorlage-URL konnte nicht geladen werden — wird ohne Stilvorlage fortgefahren'}}];
